// src/Dashboard.js
import React from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com"; // same as Login 
const green = "#0f9d58";
const lightGreen = "#eaf8f0";
const white = "#ffffff";

function Dashboard({ employee }) {
  const navigate = useNavigate();

  if (!employee) {
    return (
      <div
        style={{
          minHeight: "100vh",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: lightGreen,
          fontFamily: "Segoe UI",
        }}
      >
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div
      style={{
        fontFamily: "Segoe UI",
        background: lightGreen,
        minHeight: "100vh",
        padding: 20,
      }}
    >
      <div
        style={{
          maxWidth: 900,
          margin: "0 auto",
          background: white,
          borderRadius: 14,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
          overflow: "hidden",
        }}
      >
        {/* Header with back arrow and title */}
        <header
          style={{
            padding: 16,
            background: green,
            color: white,
            display: "flex",
            alignItems: "center",
            gap: 12,
          }}
        >
          {/* ⬅ Back to Profile */}
          <button
            onClick={() => navigate("/profile")}
            style={{
              background: "transparent",
              border: "none",
              color: "white",
              fontSize: 16,
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              gap: 4,
            }}
          >
            ⬅ Back
          </button>

          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 18, fontWeight: 700 }}>
              Employee Dashboard
            </div>
          </div>
        </header>

        {/* Main content */}
        <main style={{ padding: 18 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Employee Information</h3>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
              gap: 10,
              background: "#f9fff9",
              borderRadius: 10,
              padding: 16,
              border: `1px solid ${lightGreen}`,
            }}
          >
            <InfoRow label="Name" value={employee.name} />
            <InfoRow label="Employee ID" value={employee.empld} />
            <InfoRow label="Department" value={employee.department} />
            <InfoRow label="Role" value={employee.role} />
            <InfoRow label="Email" value={employee.email} />
            <InfoRow label="Phone" value={employee.phone} />
            <InfoRow label="Joining Date" value={employee.joiningDate} />
          </div>
        </main>
      </div>
    </div>
  );
}

function InfoRow({ label, value }) {
  return (
    <div style={{ fontSize: 14 }}>
      <span style={{ fontWeight: 600, color: "#2e7d32" }}>{label}:</span>{" "}
      <span style={{ color: "#333" }}>{value || "-"}</span>
    </div>
  );
}

export default Dashboard;
